     4→import { useEffect } from "react";
     5→import useSWR, { mutate } from "swr";
     6→import { StatsCards } from "@/components/dashboard/stats-cards";
     7→import { ReleaseTrendChart } from "@/components/dashboard/release-trend-chart";
     8→import { UnifiedFeed } from "@/components/dashboard/unified-feed";
     9→import { DashboardEmptyState } from "@/components/dashboard/empty-state";
    10→import { DiscoverySection } from "@/components/dashboard/discovery-section";
    11→import { SuggestionsSection } from "@/components/dashboard/suggestions-section";
    12→import { projects as projectsApi } from "@/lib/api/client";
    13→import { useAuth } from "@/lib/auth/context";
    14→
    15→const SSE_BASE = process.env.NEXT_PUBLIC_API_URL || "/api/v1";
    16→
    17→export default function DashboardPage() {
    18→  const { user } = useAuth();
    19→  const { data: projectsData, isLoading } = useSWR("projects-for-dashboard", () =>
    20→    projectsApi.list()
    21→  );
    22→
    23→  // Listen to SSE events and revalidate dashboard data on new releases
    24→  useEffect(() => {
    25→    let es: EventSource | null = null;
    26→    let retryTimer: ReturnType<typeof setTimeout> | null = null;
    27→
    28→    function connect() {
    29→      try {
    30→        es = new EventSource(`${SSE_BASE}/events`);
    31→        es.onmessage = () => {
    32→          // Revalidate all dashboard SWR keys on any event
    33→          mutate((key) => typeof key === "string" && (
    34→            key === "stats" ||
    35→            key.startsWith("trend-") ||
    36→            key === "unified-feed"
    37→          ), undefined, { revalidate: true });
    38→        };
    39→        es.onerror = () => {
    40→          es?.close();
    41→          retryTimer = setTimeout(connect, 5000);
    42→        };
    43→      } catch {
    44→        retryTimer = setTimeout(connect, 5000);
    45→      }
    46→    }
    47→
    48→    connect();
    49→    return () => {
    50→      es?.close();
    51→      if (retryTimer) clearTimeout(retryTimer);
    52→    };
    53→  }, []);
    54→
    55→  const hasProjects = !isLoading && projectsData?.data && projectsData.data.length > 0;
    56→
    57→  return (
    58→    <div className="space-y-6">
    59→      <h1
    60→        style={{
    61→          fontFamily: "var(--font-fraunces)",
    62→          fontSize: "24px",
    63→          fontWeight: 700,
    64→          color: "#111113",
    65→        }}
    66→      >
    67→        Dashboard
    68→      </h1>
    69→
    70→      {user?.github_login && user.github_login !== "dev" ? (
    71→        <SuggestionsSection showAuthTabs />
    72→      ) : (
    73→        <>
    74→          <DiscoverySection />
    75→          <SuggestionsSection />
    76→        </>
    77→      )}
    78→
    79→      {hasProjects ? (
    80→        <>
    81→          <StatsCards />
    82→          <div className="grid gap-4 lg:grid-cols-2">
    83→            <ReleaseTrendChart />
    84→            <UnifiedFeed />
    85→          </div>
    86→        </>
    87→      ) : isLoading ? (
    88→        <div
    89→          className="py-16 text-center"
    90→          style={{
    91→            fontFamily: "var(--font-dm-sans)",
    92→            fontSize: "13px",
    93→            color: "#6b7280",
    94→          }}
    95→        >
    96→          Loading...
    97→        </div>
    98→      ) : (
    99→        <DashboardEmptyState />
   100→      )}
   101→    </div>
   102→  );
